using System.Collections.Generic;
using UnityEngine;

namespace AjisaiFlow.UnityAgent.Editor
{
    internal static class SupporterData
    {
        internal struct Supporter
        {
            public string name;
            public string url;       // null = リンクなし
            public string avatarB64; // null = デフォルトアイコン
            public string message;   // null = 作者からの一言なし
        }

        // ─── 支援者リスト ───
        // 新しい支援者を追加するには、この配列にエントリを追加する。
        // avatarB64 は PNG を Base64 エンコードした文字列（任意サイズ対応）。
        internal static readonly Supporter[] All = new Supporter[]
        {
            // サンプル（実際の支援者が来たら差し替え）
            new Supporter
            {
                name = "たかすぎ",
                url = "",
                message = "初めての支援者！本当にありがとうございます！",
                avatarB64 = ""
            },
            new Supporter
            {
                name = "HiRyuuYuki（ひりゅー）",
                url = "",
                message = "ご支援ありがとうございます！開発を引き続き行っていきます！",
                avatarB64 = ""
            },
        };

        // ─── Texture2D キャッシュ ───
        private static Dictionary<string, Texture2D> _textureCache;
        private static Texture2D _defaultAvatar;

        internal static Texture2D GetAvatar(Supporter s)
        {
            if (_textureCache == null)
                _textureCache = new Dictionary<string, Texture2D>();

            if (string.IsNullOrEmpty(s.avatarB64))
                return GetDefaultAvatar();

            if (_textureCache.TryGetValue(s.name, out var cached) && cached != null)
                return cached;

            var bytes = System.Convert.FromBase64String(s.avatarB64);
            var tex = new Texture2D(2, 2, TextureFormat.RGBA32, false);
            tex.hideFlags = HideFlags.HideAndDontSave;
            tex.LoadImage(bytes);
            _textureCache[s.name] = tex;
            return tex;
        }

        private static Texture2D GetDefaultAvatar()
        {
            if (_defaultAvatar != null && _defaultAvatar)
                return _defaultAvatar;

            const int size = 64;
            const float center = (size - 1) / 2f;
            const float radius = size / 2f;

            _defaultAvatar = new Texture2D(size, size, TextureFormat.RGBA32, false);
            _defaultAvatar.hideFlags = HideFlags.HideAndDontSave;
            var bg = new Color(0.6f, 0.6f, 0.6f, 1f);
            var fg = new Color(0.85f, 0.85f, 0.85f, 1f);
            var clear = new Color(0, 0, 0, 0);

            for (int y = 0; y < size; y++)
            {
                for (int x = 0; x < size; x++)
                {
                    float dx = x - center;
                    float dy = y - center;
                    float dist = Mathf.Sqrt(dx * dx + dy * dy);
                    if (dist > radius)
                    {
                        _defaultAvatar.SetPixel(x, y, clear);
                        continue;
                    }

                    // 頭部（上半分の円）
                    float headCy = center + size * 0.12f;
                    float headR = size * 0.18f;
                    float hdx = x - center;
                    float hdy = y - headCy;
                    float headDist = Mathf.Sqrt(hdx * hdx + hdy * hdy);

                    // 胴体（下部の楕円）
                    float bodyCy = center - size * 0.22f;
                    float bodyRx = size * 0.28f;
                    float bodyRy = size * 0.18f;
                    float bdx = x - center;
                    float bdy = y - bodyCy;
                    float bodyDist = (bdx * bdx) / (bodyRx * bodyRx) + (bdy * bdy) / (bodyRy * bodyRy);

                    if (headDist <= headR || bodyDist <= 1f)
                        _defaultAvatar.SetPixel(x, y, fg);
                    else
                        _defaultAvatar.SetPixel(x, y, bg);
                }
            }

            _defaultAvatar.Apply();
            return _defaultAvatar;
        }
    }
}
